 60→impl WinMutex {
 61→    fn try_acquire(name: &str) -> Option<Self> {
 62→        let wide: Vec<u16> = name.encode_utf16().chain(std::iter::once(0)).collect();
 63→        let handle = unsafe { CreateMutexW(std::ptr::null(), 0, wide.as_ptr()) };
 64→        if handle.is_null() {
 65→            return None;
 66→        }
 67→        // Always try to acquire ownership (matches C# mutex.WaitOne(0))
 68→        let wait = unsafe { WaitForSingleObject(handle, 0) };
 69→        if wait != WAIT_OBJECT_0 && wait != WAIT_ABANDONED {
 70→            unsafe { CloseHandle(handle) };
 71→            return None;
 72→        }
 73→        Some(WinMutex { handle })
 74→    }
