189→fn trim_for_log(text: &str, max_length: usize) -> String {
190→    let trimmed = text.trim();
191→    if trimmed.is_empty() {
192→        return String::new();
193→    }
194→    let single_line: String = trimmed.replace(['\r', '\n'], " ");
195→    if single_line.len() <= max_length {
196→        single_line
197→    } else {
198→        let mut end = max_length;
199→        while !single_line.is_char_boundary(end) && end > 0 {
200→            end -= 1;
201→        }
202→        format!("{}...", &single_line[..end])
203→    }
