218→// --- Run command with timeout ---
219→fn run_command(file_name: &str, arguments: &str, timeout: Duration) -> CommandResult {
220→    use std::os::windows::process::CommandExt;
221→    use std::sync::mpsc;
222→    const CREATE_NO_WINDOW: u32 = 0x08000000;
223→
224→    let args: Vec<&str> = arguments.split_whitespace().collect();
225→    let child = Command::new(file_name)
226→        .args(&args)
227→        .stdout(std::process::Stdio::piped())
228→        .stderr(std::process::Stdio::piped())
229→        .creation_flags(CREATE_NO_WINDOW)
230→        .spawn();
231→
232→    let mut child = match child {
233→        Ok(c) => c,
234→        Err(e) => return CommandResult::failed(e.to_string()),
235→    };
236→
237→    let child_pid = child.id();
238→
239→    // Read stdout/stderr in background threads to avoid pipe buffer deadlock.
240→    // Use channels so we can collect output with a timeout (child processes
241→    // may inherit pipe handles and keep them open after the parent exits).
242→    let (stdout_tx, stdout_rx) = mpsc::channel();
243→    let (stderr_tx, stderr_rx) = mpsc::channel();
244→
245→    if let Some(out) = child.stdout.take() {
246→        thread::spawn(move || {
247→            let mut s = String::new();
248→            let mut out = out;
249→            let _ = out.read_to_string(&mut s);
250→            let _ = stdout_tx.send(s);
251→        });
252→    }
253→    if let Some(err) = child.stderr.take() {
254→        thread::spawn(move || {
255→            let mut s = String::new();
256→            let mut err = err;
257→            let _ = err.read_to_string(&mut s);
258→            let _ = stderr_tx.send(s);
259→        });
260→    }
261→
262→    let start = std::time::Instant::now();
263→    loop {
264→        match child.try_wait() {
265→            Ok(Some(status)) => {
266→                // Process exited. Give reader threads 2s to finish
267→                // (child processes may keep pipes open longer).
268→                let stdout = stdout_rx
269→                    .recv_timeout(Duration::from_secs(2))
270→                    .unwrap_or_default();
271→                let stderr = stderr_rx
272→                    .recv_timeout(Duration::from_secs(2))
273→                    .unwrap_or_default();
274→                return CommandResult::completed_result(
275→                    status.code().unwrap_or(-1),
276→                    stdout.trim().to_string(),
277→                    stderr.trim().to_string(),
278→                );
279→            }
280→            Ok(None) => {
281→                if start.elapsed() >= timeout {
282→                    // Kill entire process tree so grandchildren that inherited
283→                    // pipe handles are also terminated, preventing thread leaks.
284→                    kill_process_tree(child_pid);
285→                    let _ = child.wait();
286→                    let stdout = stdout_rx
287→                        .recv_timeout(Duration::from_secs(2))
288→                        .unwrap_or_default();
289→                    let stderr = stderr_rx
290→                        .recv_timeout(Duration::from_secs(2))
291→                        .unwrap_or_default();
292→                    return CommandResult::timed_out_result(
293→                        stdout.trim().to_string(),
294→                        stderr.trim().to_string(),
295→                    );
296→                }
297→                thread::sleep(Duration::from_millis(100));
298→            }
299→            Err(e) => return CommandResult::failed(e.to_string()),
300→        }
301→    }
302→}
