304→fn format_command_result(result: &CommandResult) -> String {
305→    let out_text = trim_for_log(&result.stdout, 160);
306→    let err_text = trim_for_log(&result.stderr, 160);
307→    let msg_text = trim_for_log(&result.error_message, 160);
308→    let exit_str = match result.exit_code {
309→        Some(code) => code.to_string(),
310→        None => "null".to_string(),
311→    };
312→    format!(
313→        "completed={}, timedOut={}, exitCode={}, stdout=\"{}\", stderr=\"{}\", error=\"{}\"",
314→        result.completed, result.timed_out, exit_str, out_text, err_text, msg_text
315→    )
316→}
