320→    sys.refresh_processes(sysinfo::ProcessesToUpdate::All, true);
321→    sys.processes()
322→        .values()
323→        .filter(|p| {
324→            let name = p.name().to_string_lossy().to_lowercase();
325→            name == "espanso"
326→                || name == "espanso.exe"
327→                || name == "espansod"
328→                || name == "espansod.exe"
329→        })
