333→fn kill_espanso_processes(sys: &mut System) -> u32 {
334→    sys.refresh_processes(sysinfo::ProcessesToUpdate::All, true);
335→    let mut killed = 0u32;
336→    let pids: Vec<sysinfo::Pid> = sys
337→        .processes()
338→        .iter()
339→        .filter(|(_, p)| {
340→            let name = p.name().to_string_lossy().to_lowercase();
341→            name == "espanso"
342→                || name == "espanso.exe"
343→                || name == "espansod"
344→                || name == "espansod.exe"
345→        })
346→        .map(|(pid, _)| *pid)
347→        .collect();
348→
349→    for pid in pids {
350→        if let Some(process) = sys.process(pid) {
351→            if process.kill() {
352→                killed += 1;
353→            } else {
354→                log(&format!("failed to kill pid={}", pid));
355→            }
356→        }
357→    }
358→    killed
359→}
