361→// --- Espanso log analysis ---
362→fn read_tail_text(path: &PathBuf, max_bytes: u64) -> Result<String, std::io::Error> {
363→    let mut file = File::open(path)?;
364→    let length = file.metadata()?.len();
365→    let bytes_to_read = length.min(max_bytes);
366→    if bytes_to_read == 0 {
367→        return Ok(String::new());
368→    }
369→
370→    file.seek(SeekFrom::End(-(bytes_to_read as i64)))?;
371→    let mut buffer = vec![0u8; bytes_to_read as usize];
372→    let read = file.read(&mut buffer)?;
373→    let mut text = String::from_utf8_lossy(&buffer[..read]).to_string();
374→
375→    if length > max_bytes {
376→        if let Some(pos) = text.find('\n') {
377→            if pos + 1 < text.len() {
378→                text = text[pos + 1..].to_string();
379→            }
380→        }
381→    }
382→
383→    Ok(text)
384→}
