386→fn is_recent_espanso_log_line(line: &str) -> bool {
387→    if line.len() < 8 || !line.is_char_boundary(8) {
388→        return false;
389→    }
390→
391→    let time_str = &line[..8];
392→    let parsed_time = match NaiveTime::parse_from_str(time_str, "%H:%M:%S") {
393→        Ok(t) => t,
394→        Err(_) => return false,
395→    };
396→
397→    let now = Local::now();
398→    let today = now.date_naive();
399→    let mut line_dt = today
400→        .and_time(parsed_time)
401→        .and_local_timezone(Local)
402→        .single();
403→
404→    if let Some(dt) = line_dt {
405→        if dt > now + chrono::Duration::minutes(1) {
406→            line_dt = (today - chrono::Duration::days(1))
407→                .and_time(parsed_time)
408→                .and_local_timezone(Local)
409→                .single();
410→        }
411→    }
412→
413→    match line_dt {
414→        Some(dt) => {
415→            let diff = now.signed_duration_since(dt);
416→            diff >= chrono::Duration::zero()
417→                && diff <= chrono::Duration::minutes(CRITICAL_LOG_LOOKBACK_MINUTES)
418→        }
419→        None => false,
420→    }
421→}
