423→fn is_critical_espanso_log_line(line: &str) -> bool {
424→    let lower = line.to_lowercase();
425→    lower.contains("[error]")
426→        && lower.contains("could not restart worker")
427→        && is_recent_espanso_log_line(line)
428→}
