430→fn get_latest_critical_espanso_log_line() -> Option<String> {
431→    let path = espanso_log_path();
432→    if !path.exists() {
433→        return None;
434→    }
435→
436→    let tail = match read_tail_text(&path, ESPANSO_LOG_TAIL_BYTES) {
437→        Ok(t) => t,
438→        Err(e) => {
439→            log(&format!(
440→                "failed to read espanso.log: {}",
441→                trim_for_log(&e.to_string(), 200)
442→            ));
443→            return None;
444→        }
445→    };
446→
447→    let lines: Vec<&str> = tail.split(['\r', '\n']).filter(|l| !l.is_empty()).collect();
448→
449→    for line in lines.iter().rev() {
450→        if is_critical_espanso_log_line(line) {
451→            return Some(trim_for_log(line, 220));
452→        }
453→    }
454→
455→    None
456→}
