458→// --- Health check ---
459→struct HealthState {
460→    last_critical_log_line: Option<String>,
461→    sys: System,
462→    espanso_cli: String,
463→}
464→
465→impl HealthState {
466→    fn new() -> Self {
467→        Self {
468→            last_critical_log_line: None,
469→            sys: System::new(),
470→            espanso_cli: resolve_espanso_cli_path(),
471→        }
472→    }
473→
474→    fn is_healthy(&mut self) -> (bool, String) {
475→        let status_result = run_command(
476→            &self.espanso_cli,
477→            "service status",
478→            Duration::from_secs(STATUS_TIMEOUT_SECONDS),
479→        );
480→
481→        let service_running = status_result.completed
482→            && status_result
483→                .stdout
484→                .to_lowercase()
485→                .contains("espanso is running");
486→
487→        let process_count = get_espanso_process_count(&mut self.sys);
488→        let has_required = process_count >= EXPECTED_ESPANSO_PROCESS_COUNT;
489→        let basic_healthy = service_running && has_required;
490→
491→        if basic_healthy {
492→            if let Some(critical_line) = get_latest_critical_espanso_log_line() {
493→                let is_new = self.last_critical_log_line.as_ref() != Some(&critical_line);
494→                if is_new {
495→                    self.last_critical_log_line = Some(critical_line.clone());
496→                    let detail = format!(
497→                        "criticalEspansoError=\"{}\", serviceRunning={}, processCount={}, status={}",
498→                        critical_line,
499→                        service_running,
500→                        process_count,
501→                        format_command_result(&status_result)
502→                    );
503→                    return (false, detail);
504→                }
505→            }
506→        }
507→
508→        let detail = format!(
509→            "serviceRunning={}, processCount={}, status={}",
510→            service_running,
511→            process_count,
512→            format_command_result(&status_result)
513→        );
514→        (basic_healthy, detail)
515→    }
516→
517→    fn ensure_healthy(&mut self) -> bool {
518→        let (healthy, detail) = self.is_healthy();
519→        if healthy {
520→            log(&format!("healthy: {}", detail));
521→            return true;
522→        }
523→
524→        log(&format!("unhealthy detected: {}", detail));
525→
526→        for attempt in 1..=RECOVERY_RETRY_COUNT {
527→            let killed = kill_espanso_processes(&mut self.sys);
528→            log(&format!(
529→                "recovery attempt {}/{}: killed espanso processes={}.",
530→                attempt, RECOVERY_RETRY_COUNT, killed
531→            ));
532→
533→            thread::sleep(RECOVERY_KILL_WAIT);
534→
535→            let start_result = run_command(
536→                &self.espanso_cli,
537→                "service start --unmanaged",
538→                Duration::from_secs(START_TIMEOUT_SECONDS),
539→            );
540→
541→            log(&format!(
542→                "recovery attempt {}/{}: service start result={}.",
543→                attempt,
544→                RECOVERY_RETRY_COUNT,
545→                format_command_result(&start_result)
546→            ));
547→
548→            thread::sleep(RECOVERY_START_WAIT);
549→
550→            let (recovered, recovered_detail) = self.is_healthy();
551→            if recovered {
552→                log(&format!(
553→                    "recovery succeeded on attempt {}: {}",
554→                    attempt, recovered_detail
555→                ));
556→                return true;
557→            }
558→
559→            log(&format!(
560→                "recovery attempt {}/{} failed.",
561→                attempt, RECOVERY_RETRY_COUNT
562→            ));
563→        }
564→
565→        log("recovery failed after all retries.");
566→        false
567→    }
568→}
