use serde::{Deserialize, Serialize};
use std::fs;
use std::io::{self, Write};
use std::process;

#[derive(Deserialize)]
struct InputEntry {
    key: String,
    command: String,
    #[serde(default)]
    when: Option<String>,
}

#[derive(Serialize)]
struct OutputEntry {
    key: String,
    command: String,
    #[serde(skip_serializing_if = "Option::is_none")]
    when: Option<String>,
}

fn main() {
    let args: Vec<String> = std::env::args().collect();

    if args.len() < 2 {
        eprintln!("Usage: disable-keybindings <input.json> [-o <output.json>]");
        process::exit(1);
    }

    let input_path = &args[1];
    let output_path = args
        .iter()
        .position(|a| a == "-o")
        .and_then(|i| args.get(i + 1));

    let content = fs::read_to_string(input_path).unwrap_or_else(|e| {
        eprintln!("Error reading {input_path}: {e}");
        process::exit(1);
    });

    // VSCode default keybindings JSON may have trailing commas or comments.
    // Strip single-line comments (// ...) before parsing.
    let cleaned: String = content
        .lines()
        .map(|line| {
            // Remove single-line comments outside of strings (simple heuristic)
            if let Some(pos) = find_comment_start(line) {
                &line[..pos]
            } else {
                line
            }
        })
        .collect::<Vec<_>>()
        .join("\n");

    // serde_json doesn't support trailing commas, so remove them.
    let cleaned = remove_trailing_commas(&cleaned);

    let entries: Vec<InputEntry> = serde_json::from_str(&cleaned).unwrap_or_else(|e| {
        eprintln!("Error parsing JSON: {e}");
        process::exit(1);
    });

    let disabled: Vec<OutputEntry> = entries
        .into_iter()
        .filter(|entry| !entry.command.starts_with('-'))
        .map(|entry| OutputEntry {
            key: entry.key,
            command: format!("-{}", entry.command),
            when: entry.when,
        })
        .collect();

    let json = serde_json::to_string_pretty(&disabled).expect("Failed to serialize output");

    match output_path {
        Some(path) => {
            fs::write(path, json.as_bytes()).unwrap_or_else(|e| {
                eprintln!("Error writing {path}: {e}");
                process::exit(1);
            });
            eprintln!("Wrote {} entries to {path}", disabled.len());
        }
        None => {
            io::stdout()
                .write_all(json.as_bytes())
                .expect("Failed to write to stdout");
        }
    }
}

/// Find the start position of a `//` comment that is NOT inside a JSON string.
fn find_comment_start(line: &str) -> Option<usize> {
    let mut in_string = false;
    let mut escape = false;
    let bytes = line.as_bytes();

    for i in 0..bytes.len() {
        let ch = bytes[i];
        if escape {
            escape = false;
            continue;
        }
        if ch == b'\\' && in_string {
            escape = true;
            continue;
        }
        if ch == b'"' {
            in_string = !in_string;
            continue;
        }
        if !in_string && ch == b'/' && i + 1 < bytes.len() && bytes[i + 1] == b'/' {
            return Some(i);
        }
    }
    None
}

/// Remove trailing commas before `]` or `}` (with optional whitespace between).
fn remove_trailing_commas(s: &str) -> String {
    let bytes = s.as_bytes();
    let mut result = Vec::with_capacity(bytes.len());
    let mut in_string = false;
    let mut escape = false;

    for i in 0..bytes.len() {
        let ch = bytes[i];
        if escape {
            escape = false;
            result.push(ch);
            continue;
        }
        if ch == b'\\' && in_string {
            escape = true;
            result.push(ch);
            continue;
        }
        if ch == b'"' {
            in_string = !in_string;
            result.push(ch);
            continue;
        }
        if !in_string && ch == b',' {
            // Look ahead for `]` or `}`, skipping whitespace
            let mut j = i + 1;
            while j < bytes.len()
                && (bytes[j] == b' ' || bytes[j] == b'\t' || bytes[j] == b'\n' || bytes[j] == b'\r')
            {
                j += 1;
            }
            if j < bytes.len() && (bytes[j] == b']' || bytes[j] == b'}') {
                // Skip this comma
                continue;
            }
        }
        result.push(ch);
    }
    String::from_utf8(result).expect("Invalid UTF-8 after trailing comma removal")
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_find_comment_start() {
        assert_eq!(find_comment_start("// this is a comment"), Some(0));
        assert_eq!(
            find_comment_start(r#"  "key": "ctrl+a", // inline comment"#),
            Some(19)
        );
        assert_eq!(find_comment_start(r#"  "key": "ctrl+//a""#), None);
        assert_eq!(find_comment_start(r#"  "key": "ctrl+a""#), None);
    }

    #[test]
    fn test_remove_trailing_commas() {
        let input = r#"[{"a": 1,}, {"b": 2,},]"#;
        let result = remove_trailing_commas(input);
        assert_eq!(result, r#"[{"a": 1}, {"b": 2}]"#);
    }

    #[test]
    fn test_remove_trailing_commas_preserves_strings() {
        let input = r#"[{"a": "hello,"}]"#;
        let result = remove_trailing_commas(input);
        assert_eq!(result, r#"[{"a": "hello,"}]"#);
    }

    #[test]
    fn test_disable_command() {
        let json = r#"[
            { "key": "ctrl+a", "command": "editor.action.selectAll" },
            { "key": "ctrl+c", "command": "-editor.action.clipboardCopy", "when": "textInputFocus" }
        ]"#;
        let entries: Vec<InputEntry> = serde_json::from_str(json).unwrap();
        let disabled: Vec<OutputEntry> = entries
            .into_iter()
            .filter(|e| !e.command.starts_with('-'))
            .map(|e| OutputEntry {
                key: e.key,
                command: format!("-{}", e.command),
                when: e.when,
            })
            .collect();

        assert_eq!(disabled.len(), 1);
        assert_eq!(disabled[0].command, "-editor.action.selectAll");
        assert!(disabled[0].when.is_none());
    }

    #[test]
    fn test_when_preserved() {
        let json = r#"[
            { "key": "ctrl+s", "command": "workbench.action.files.save", "when": "editorTextFocus" }
        ]"#;
        let entries: Vec<InputEntry> = serde_json::from_str(json).unwrap();
        let disabled: Vec<OutputEntry> = entries
            .into_iter()
            .filter(|e| !e.command.starts_with('-'))
            .map(|e| OutputEntry {
                key: e.key,
                command: format!("-{}", e.command),
                when: e.when,
            })
            .collect();

        assert_eq!(disabled.len(), 1);
        assert_eq!(disabled[0].when.as_deref(), Some("editorTextFocus"));
    }
}

