import unittest

from generate_powershell_open import (
    build_command,
    build_output,
    parse_entries,
    strip_one_pair,
)


class TestStripOnePair(unittest.TestCase):
    def test_single_quotes(self):
        self.assertEqual(strip_one_pair("'hello'"), "hello")

    def test_double_quotes(self):
        self.assertEqual(strip_one_pair('"hello"'), "hello")

    def test_no_quotes(self):
        self.assertEqual(strip_one_pair("hello"), "hello")

    def test_mismatched_quotes(self):
        self.assertEqual(strip_one_pair("'hello\""), "'hello\"")

    def test_empty_quotes(self):
        self.assertEqual(strip_one_pair("''"), "")

    def test_single_char(self):
        self.assertEqual(strip_one_pair("x"), "x")


class TestParseEntries(unittest.TestCase):
    def test_basic_entry_with_cmd(self):
        text = (
            "matches:\n"
            '  - trigger: ":foo"\n'
            '    replace: "{{run}}"\n'
            "    vars:\n"
            "      - name: run\n"
            "        type: shell\n"
            "        params:\n"
            "          shell: powershell\n"
            '          cmd: \'& "code.cmd" "C:\\path"\'\n'
        )
        entries = parse_entries(text)
        self.assertEqual(len(entries), 1)
        self.assertEqual(entries[0]["trigger"], ":foo")

    def test_entry_with_replace_only(self):
        text = '  - trigger: ":stae"\n    replace: "shell:startup\\n"\n'
        entries = parse_entries(text)
        self.assertEqual(len(entries), 1)
        self.assertEqual(entries[0]["trigger"], ":stae")
        self.assertEqual(entries[0]["replace"], "shell:startup\\n")

    def test_comments_preserved(self):
        text = '  # section header\n  - trigger: ":bar"\n    replace: test\n'
        entries = parse_entries(text)
        self.assertEqual(len(entries), 1)
        self.assertEqual(entries[0]["comments"], ["# section header"])

    def test_multiple_entries(self):
        text = '  - trigger: ":a"\n    replace: x\n  - trigger: ":b"\n    replace: y\n'
        entries = parse_entries(text)
        self.assertEqual(len(entries), 2)
        self.assertEqual(entries[0]["trigger"], ":a")
        self.assertEqual(entries[1]["trigger"], ":b")


class TestBuildCommand(unittest.TestCase):
    def test_startup_path(self):
        entry = {"replace": "shell:startup\\n", "cmd": None}
        result = build_command(entry)
        self.assertIn("Start-Process powershell", result)
        self.assertIn("startup", result)

    def test_code_cmd_entry(self):
        entry = {
            "replace": "{{run}}",
            "cmd": '& "$env:LOCALAPPDATA\\Programs\\Microsoft VS Code\\bin\\code.cmd" "$env:USERPROFILE\\Desktop"',
        }
        result = build_command(entry)
        self.assertIn("Start-Process powershell", result)
        self.assertIn("$env:USERPROFILE\\Desktop", result)

    def test_ahk_entry(self):
        entry = {
            "replace": "{{run}}",
            "cmd": '& "C:\\path\\to\\test.ahk"',
        }
        result = build_command(entry)
        self.assertIn("Start-Process -FilePath", result)

    def test_local_variable_skipped(self):
        entry = {
            "replace": "{{run}}",
            "cmd": '& "$env:LOCALAPPDATA\\Programs\\Microsoft VS Code\\bin\\code.cmd" "$y\\$m"',
        }
        result = build_command(entry)
        self.assertIsNone(result)

    def test_no_match_returns_none(self):
        entry = {"replace": "{{run}}", "cmd": "echo hello"}
        result = build_command(entry)
        self.assertIsNone(result)


class TestBuildOutput(unittest.TestCase):
    def test_header_lines(self):
        output = build_output([])
        self.assertIn("AUTO-GENERATED", output)
        self.assertIn("matches:", output)

    def test_trigger_prefix_replaced(self):
        entries = [
            {
                "trigger": ":des",
                "replace": "{{run}}",
                "cmd": '& "$env:LOCALAPPDATA\\Programs\\Microsoft VS Code\\bin\\code.cmd" "$env:USERPROFILE\\Desktop"',
                "comments": [],
            }
        ]
        output = build_output(entries)
        self.assertIn(":sdes", output)
        self.assertNotIn('":des"', output)

    def test_non_colon_trigger_skipped(self):
        entries = [
            {
                "trigger": "foo",
                "replace": "{{run}}",
                "cmd": '& "code.cmd" "C:\\path"',
                "comments": [],
            }
        ]
        output = build_output(entries)
        self.assertNotIn("foo", output.split("matches:")[1])

    def test_ends_with_newline(self):
        output = build_output([])
        self.assertTrue(output.endswith("\n"))


if __name__ == "__main__":
    unittest.main()
